     1→# Rate Limiting Implementation Guide
     2→
     3→**Work Item**: Azure DevOps #2960
     4→**Date**: 2026-01-17
     5→**Status**: Ready for Implementation
     6→
     7→---
     8→
     9→## Quick Start
    10→
    11→This guide provides step-by-step instructions for implementing rate limiting in the Todo App authentication system.
    12→
    13→**Estimated Implementation Time**: 4-6 hours
    14→
    15→---
    16→
    17→## Prerequisites
    18→
    19→- [x] Database schema already includes `LoginAttempt` table
    20→- [x] Password reset tokens already using bcrypt hashing
    21→- [x] Bcrypt library already installed (`bcrypt@6.0.0`)
    22→- [x] Prisma ORM configured
    23→
    24→**No database migrations or dependency installations needed!**
    25→
    26→---
    27→
    28→## Implementation Steps
    29→
    30→### Step 1: Create IP Address Utility
    31→
    32→Create `/lib/ip-address.ts`:
    33→
    34→```typescript
    35→import { NextRequest } from 'next/server';
    36→
    37→/**
    38→ * Extract IP address from request
    39→ * Handles proxy headers (X-Forwarded-For, X-Real-IP)
    40→ *
    41→ * @param request - NextRequest or standard Request object
    42→ * @returns IP address string
    43→ */
    44→export function getIpAddress(request: NextRequest | Request): string {
    45→  // Priority 1: X-Forwarded-For (most common with proxies/load balancers)
    46→  const forwardedFor = request.headers.get('x-forwarded-for');
    47→  if (forwardedFor) {
    48→    // X-Forwarded-For can be a comma-separated list: "client, proxy1, proxy2"
    49→    // We want the first one (original client)
    50→    return forwardedFor.split(',')[0].trim();
    51→  }
    52→
    53→  // Priority 2: X-Real-IP (nginx specific)
    54→  const realIp = request.headers.get('x-real-ip');
    55→  if (realIp) {
    56→    return realIp.trim();
    57→  }
    58→
    59→  // Priority 3: CF-Connecting-IP (Cloudflare)
    60→  const cfIp = request.headers.get('cf-connecting-ip');
    61→  if (cfIp) {
    62→    return cfIp.trim();
    63→  }
    64→
    65→  // Priority 4: Fallback to unknown
    66→  return '0.0.0.0';
    67→}
    68→
    69→/**
    70→ * Mask IP address for logging (privacy)
    71→ * Example: 192.168.1.100 -> 192.168.x.x
    72→ */
    73→export function maskIpAddress(ip: string): string {
    74→  const parts = ip.split('.');
    75→  if (parts.length === 4) {
    76→    return `${parts[0]}.${parts[1]}.x.x`;
    77→  }
    78→  return 'x.x.x.x';
    79→}
    80→```
    81→
    82→---
    83→
    84→### Step 2: Create Rate Limiting Service
    85→
    86→Create `/lib/rate-limit.ts`:
    87→
    88→```typescript
    89→import { prisma } from '@/lib/prisma';
    90→
    91→// Configuration constants
    92→const EMAIL_RATE_LIMIT = 5;           // Max failed attempts per email
    93→const IP_RATE_LIMIT = 10;             // Max failed attempts per IP
    94→const LOCKOUT_DURATION_MS = 15 * 60 * 1000;  // 15 minutes in milliseconds
    95→
    96→export interface RateLimitResult {
    97→  isLocked: boolean;
    98→  remainingMinutes: number;
    99→  lockedBy: 'email' | 'ip' | null;
   100→}
   101→
   102→/**
   103→ * Check if email or IP is rate limited
   104→ *
   105→ * @param email - Email address attempting to login
   106→ * @param ipAddress - IP address of request
   107→ * @returns Rate limit status with remaining time if locked
   108→ */
   109→export async function checkRateLimit(
   110→  email: string,
   111→  ipAddress: string
   112→): Promise<RateLimitResult> {
   113→  const cutoffTime = new Date(Date.now() - LOCKOUT_DURATION_MS);
   114→
   115→  // Check email-based rate limit
   116→  const emailAttempts = await prisma.loginAttempt.count({
   117→    where: {
   118→      email: email.toLowerCase(),
   119→      success: false,
   120→      createdAt: {
   121→        gte: cutoffTime,
   122→      },
   123→    },
   124→  });
   125→
   126→  if (emailAttempts >= EMAIL_RATE_LIMIT) {
   127→    // Find the oldest failed attempt to calculate remaining time
   128→    const oldestAttempt = await prisma.loginAttempt.findFirst({
   129→      where: {
   130→        email: email.toLowerCase(),
   131→        success: false,
   132→        createdAt: {
   133→          gte: cutoffTime,
   134→        },
   135→      },
   136→      orderBy: {
   137→        createdAt: 'asc',
   138→      },
   139→    });
   140→
   141→    if (oldestAttempt) {
   142→      const unlockTime = new Date(
   143→        oldestAttempt.createdAt.getTime() + LOCKOUT_DURATION_MS
   144→      );
   145→      const remainingMs = unlockTime.getTime() - Date.now();
   146→      const remainingMinutes = Math.ceil(remainingMs / 60000);
   147→
   148→      return {
   149→        isLocked: true,
   150→        remainingMinutes: Math.max(1, remainingMinutes),
   151→        lockedBy: 'email',
   152→      };
   153→    }
   154→  }
   155→
   156→  // Check IP-based rate limit
   157→  const ipAttempts = await prisma.loginAttempt.count({
   158→    where: {
   159→      ipAddress,
   160→      success: false,
   161→      createdAt: {
   162→        gte: cutoffTime,
   163→      },
   164→    },
   165→  });
   166→
   167→  if (ipAttempts >= IP_RATE_LIMIT) {
   168→    const oldestAttempt = await prisma.loginAttempt.findFirst({
   169→      where: {
   170→        ipAddress,
   171→        success: false,
   172→        createdAt: {
   173→          gte: cutoffTime,
   174→        },
   175→      },
   176→      orderBy: {
   177→        createdAt: 'asc',
   178→      },
   179→    });
   180→
   181→    if (oldestAttempt) {
   182→      const unlockTime = new Date(
   183→        oldestAttempt.createdAt.getTime() + LOCKOUT_DURATION_MS
   184→      );
   185→      const remainingMs = unlockTime.getTime() - Date.now();
   186→      const remainingMinutes = Math.ceil(remainingMs / 60000);
   187→
   188→      return {
   189→        isLocked: true,
   190→        remainingMinutes: Math.max(1, remainingMinutes),
   191→        lockedBy: 'ip',
   192→      };
   193→    }
   194→  }
   195→
   196→  // Not rate limited
   197→  return {
   198→    isLocked: false,
   199→    remainingMinutes: 0,
   200→    lockedBy: null,
   201→  };
   202→}
   203→
   204→/**
   205→ * Record a login attempt (success or failure)
   206→ *
   207→ * @param email - Email address
   208→ * @param ipAddress - IP address
   209→ * @param success - Whether the login was successful
   210→ */
   211→export async function recordLoginAttempt(
   212→  email: string,
   213→  ipAddress: string,
   214→  success: boolean
   215→): Promise<void> {
   216→  await prisma.loginAttempt.create({
   217→    data: {
   218→      email: email.toLowerCase(),
   219→      ipAddress,
   220→      success,
   221→    },
   222→  });
   223→
   224→  // Optional: Clean up old successful attempts to reduce database size
   225→  // Only keep failed attempts for rate limiting
   226→  if (success) {
   227→    // Delete successful attempts older than 24 hours
   228→    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
   229→    await prisma.loginAttempt.deleteMany({
   230→      where: {
   231→        success: true,
   232→        createdAt: {
   233→          lt: oneDayAgo,
   234→        },
   235→      },
   236→    });
   237→  }
   238→}
   239→
   240→/**
   241→ * Get remaining lockout time for an email
   242→ * Used to display helpful error messages
   243→ *
   244→ * @param email - Email address
   245→ * @returns Remaining minutes or null if not locked
   246→ */
   247→export async function getRemainingLockoutTime(
   248→  email: string
   249→): Promise<number | null> {
   250→  const cutoffTime = new Date(Date.now() - LOCKOUT_DURATION_MS);
   251→
   252→  const oldestAttempt = await prisma.loginAttempt.findFirst({
   253→    where: {
   254→      email: email.toLowerCase(),
   255→      success: false,
   256→      createdAt: {
   257→        gte: cutoffTime,
   258→      },
   259→    },
   260→    orderBy: {
   261→      createdAt: 'asc',
   262→    },
   263→  });
   264→
   265→  if (!oldestAttempt) {
   266→    return null;
   267→  }
   268→
   269→  const unlockTime = new Date(
   270→    oldestAttempt.createdAt.getTime() + LOCKOUT_DURATION_MS
   271→  );
   272→  const remainingMs = unlockTime.getTime() - Date.now();
   273→
   274→  if (remainingMs <= 0) {
   275→    return null;
   276→  }
   277→
   278→  return Math.ceil(remainingMs / 60000);
   279→}
   280→
   281→/**
   282→ * Clean up old login attempts (maintenance function)
   283→ * Can be called periodically to keep database size manageable
   284→ */
   285→export async function cleanupOldAttempts(): Promise<number> {
   286→  const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
   287→
   288→  const result = await prisma.loginAttempt.deleteMany({
   289→    where: {
   290→      createdAt: {
   291→        lt: oneDayAgo,
   292→      },
   293→    },
   294→  });
   295→
   296→  return result.count;
   297→}
   298→```
