# Rate Limiting Implementation Guide

**Work Item**: Azure DevOps #2960
**Date**: 2026-01-17
**Status**: Ready for Implementation

---

## Quick Start

This guide provides step-by-step instructions for implementing rate limiting in the Todo App authentication system.

**Estimated Implementation Time**: 4-6 hours

---

## Prerequisites

- [x] Database schema already includes `LoginAttempt` table
- [x] Password reset tokens already using bcrypt hashing
- [x] Bcrypt library already installed (`bcrypt@6.0.0`)
- [x] Prisma ORM configured

**No database migrations or dependency installations needed!**

---

## Implementation Steps

### Step 1: Create IP Address Utility

Create `/lib/ip-address.ts`:

```typescript
import { NextRequest } from 'next/server';

/**
 * Extract IP address from request
 * Handles proxy headers (X-Forwarded-For, X-Real-IP)
 *
 * @param request - NextRequest or standard Request object
 * @returns IP address string
 */
export function getIpAddress(request: NextRequest | Request): string {
  // Priority 1: X-Forwarded-For (most common with proxies/load balancers)
  const forwardedFor = request.headers.get('x-forwarded-for');
  if (forwardedFor) {
    // X-Forwarded-For can be a comma-separated list: "client, proxy1, proxy2"
    // We want the first one (original client)
    return forwardedFor.split(',')[0].trim();
  }

  // Priority 2: X-Real-IP (nginx specific)
  const realIp = request.headers.get('x-real-ip');
  if (realIp) {
    return realIp.trim();
  }

  // Priority 3: CF-Connecting-IP (Cloudflare)
  const cfIp = request.headers.get('cf-connecting-ip');
  if (cfIp) {
    return cfIp.trim();
  }

  // Priority 4: Fallback to unknown
  return '0.0.0.0';
}

/**
 * Mask IP address for logging (privacy)
 * Example: 192.168.1.100 -> 192.168.x.x
 */
export function maskIpAddress(ip: string): string {
  const parts = ip.split('.');
  if (parts.length === 4) {
    return `${parts[0]}.${parts[1]}.x.x`;
  }
  return 'x.x.x.x';
}
```

---

### Step 2: Create Rate Limiting Service

Create `/lib/rate-limit.ts`:

```typescript
import { prisma } from '@/lib/prisma';

// Configuration constants
const EMAIL_RATE_LIMIT = 5;           // Max failed attempts per email
const IP_RATE_LIMIT = 10;             // Max failed attempts per IP
const LOCKOUT_DURATION_MS = 15 * 60 * 1000;  // 15 minutes in milliseconds

export interface RateLimitResult {
  isLocked: boolean;
  remainingMinutes: number;
  lockedBy: 'email' | 'ip' | null;
}

/**
 * Check if email or IP is rate limited
 *
 * @param email - Email address attempting to login
 * @param ipAddress - IP address of request
 * @returns Rate limit status with remaining time if locked
 */
export async function checkRateLimit(
  email: string,
  ipAddress: string
): Promise<RateLimitResult> {
  const cutoffTime = new Date(Date.now() - LOCKOUT_DURATION_MS);

  // Check email-based rate limit
  const emailAttempts = await prisma.loginAttempt.count({
    where: {
      email: email.toLowerCase(),
      success: false,
      createdAt: {
        gte: cutoffTime,
      },
    },
  });

  if (emailAttempts >= EMAIL_RATE_LIMIT) {
    // Find the oldest failed attempt to calculate remaining time
    const oldestAttempt = await prisma.loginAttempt.findFirst({
      where: {
        email: email.toLowerCase(),
        success: false,
        createdAt: {
          gte: cutoffTime,
        },
      },
      orderBy: {
        createdAt: 'asc',
      },
    });

    if (oldestAttempt) {
      const unlockTime = new Date(
        oldestAttempt.createdAt.getTime() + LOCKOUT_DURATION_MS
      );
      const remainingMs = unlockTime.getTime() - Date.now();
      const remainingMinutes = Math.ceil(remainingMs / 60000);

      return {
        isLocked: true,
        remainingMinutes: Math.max(1, remainingMinutes),
        lockedBy: 'email',
      };
    }
  }

  // Check IP-based rate limit
  const ipAttempts = await prisma.loginAttempt.count({
    where: {
      ipAddress,
      success: false,
      createdAt: {
        gte: cutoffTime,
      },
    },
  });

  if (ipAttempts >= IP_RATE_LIMIT) {
    const oldestAttempt = await prisma.loginAttempt.findFirst({
      where: {
        ipAddress,
        success: false,
        createdAt: {
          gte: cutoffTime,
        },
      },
      orderBy: {
        createdAt: 'asc',
      },
    });

    if (oldestAttempt) {
      const unlockTime = new Date(
        oldestAttempt.createdAt.getTime() + LOCKOUT_DURATION_MS
      );
      const remainingMs = unlockTime.getTime() - Date.now();
      const remainingMinutes = Math.ceil(remainingMs / 60000);

      return {
        isLocked: true,
        remainingMinutes: Math.max(1, remainingMinutes),
        lockedBy: 'ip',
      };
    }
  }

  // Not rate limited
  return {
    isLocked: false,
    remainingMinutes: 0,
    lockedBy: null,
  };
}

/**
 * Record a login attempt (success or failure)
 *
 * @param email - Email address
 * @param ipAddress - IP address
 * @param success - Whether the login was successful
 */
export async function recordLoginAttempt(
  email: string,
  ipAddress: string,
  success: boolean
): Promise<void> {
  await prisma.loginAttempt.create({
    data: {
      email: email.toLowerCase(),
      ipAddress,
      success,
    },
  });

  // Optional: Clean up old successful attempts to reduce database size
  // Only keep failed attempts for rate limiting
  if (success) {
    // Delete successful attempts older than 24 hours
    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
    await prisma.loginAttempt.deleteMany({
      where: {
        success: true,
        createdAt: {
          lt: oneDayAgo,
        },
      },
    });
  }
}

/**
 * Get remaining lockout time for an email
 * Used to display helpful error messages
 *
 * @param email - Email address
 * @returns Remaining minutes or null if not locked
 */
export async function getRemainingLockoutTime(
  email: string
): Promise<number | null> {
  const cutoffTime = new Date(Date.now() - LOCKOUT_DURATION_MS);

  const oldestAttempt = await prisma.loginAttempt.findFirst({
    where: {
      email: email.toLowerCase(),
      success: false,
      createdAt: {
        gte: cutoffTime,
      },
    },
    orderBy: {
      createdAt: 'asc',
    },
  });

  if (!oldestAttempt) {
    return null;
  }

  const unlockTime = new Date(
    oldestAttempt.createdAt.getTime() + LOCKOUT_DURATION_MS
  );
  const remainingMs = unlockTime.getTime() - Date.now();

  if (remainingMs <= 0) {
    return null;
  }

  return Math.ceil(remainingMs / 60000);
}

/**
 * Clean up old login attempts (maintenance function)
 * Can be called periodically to keep database size manageable
 */
export async function cleanupOldAttempts(): Promise<number> {
  const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);

  const result = await prisma.loginAttempt.deleteMany({
    where: {
      createdAt: {
        lt: oneDayAgo,
      },
    },
  });

  return result.count;
}
